const draft = $('Fetch Approved Draft').item.json;
const clockifyUserId = $json.clockify_user_id;
if (!clockifyUserId) {
  throw new Error('F-07 delivery aborted: no clockify_user_id in roster for approver_discord_id ' + draft.approver_discord_id);
}

const contextJson = typeof draft.context_json === 'object' ? draft.context_json : {};

// CRIT-03: validate draft_hours -- reject 0, negative, non-finite, >16h values
const rawDraftHours = Number(contextJson.draft_hours);
const draftHours = (isFinite(rawDraftHours) && rawDraftHours > 0 && rawDraftHours <= 16) ? rawDraftHours : 8;

// MED-03: strip non-printable chars and clamp before it reaches Clockify description
const featureArea = String(contextJson.feature_area || 'General').replace(/[^\x20-\x7E]/g, '').slice(0, 80) || 'General';

// CRIT-02: cap edited hours at 16h (same as draftHours max)
let finalHours = draftHours;
const editedText = String(draft.edited_text || '').trim();
const hourMatch = editedText.match(/^edit\s+(\d+(?:\.\d+)?)\s*h(?:ours?)?/i);
if (hourMatch) {
  const parsed = parseFloat(hourMatch[1]);
  if (!isNaN(parsed) && parsed > 0 && parsed <= 16) {
    finalHours = parsed;
  }
}

// Compute start/end based on EOD_TIME env var (e.g., '17:00' or '17:00:00')
const eodTime = String($env.EOD_TIME || '17:00');
const [eodHour, eodMin] = eodTime.split(':').map(n => parseInt(n, 10));
const today = new Date();
const endTime  = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), today.getUTCDate(), eodHour || 17, eodMin || 0, 0));
const startTime = new Date(endTime.getTime() - finalHours * 3_600_000);

// CRIT-02: cross-day guard -- reject entries that would cross midnight
if (startTime.getUTCDate() !== endTime.getUTCDate()) {
  throw new Error('F-07 delivery aborted: ' + finalHours + 'h entry would cross midnight (end=' + endTime.toISOString() + '). Reduce hours or check EOD_TIME config.');
}

return [{ json: {
  draft_id:            draft.draft_id,
  discord_channel_id:  draft.discord_channel_id,
  clockify_user_id:    clockifyUserId,
  feature_area:        featureArea,
  final_hours:         finalHours,
  description:         featureArea !== 'General' ? 'Work on the ' + featureArea + ' feature' : 'General development work',
  start_iso:           startTime.toISOString(),
  end_iso:             endTime.toISOString()
} }];

